const PROCESSING_FEE = 5;
const SWORD_PREMIUM_NEWCOMER_PLAIN = 115;
const AMULET_PREMIUM_NEWCOMER_PLAIN = 71;
const STAFF_PREMIUM_NEWCOMER_PLAIN = 93;

export function quote(_customer: Customer, items: Item[]): number {
  if (items.length === 0) return PROCESSING_FEE;
  if (items[0].type === "amulet") return AMULET_PREMIUM_NEWCOMER_PLAIN;
  if (items[0].type === "staff") return STAFF_PREMIUM_NEWCOMER_PLAIN;
  return SWORD_PREMIUM_NEWCOMER_PLAIN;
}
